index 0000000..5b2a961
--- /dev/null
+++ b/extension_cpp_stable/extension_cpp_stable/csrc/cuda/muladd.cu
@@ -0,0 +1,143 @@
+#include <torch/csrc/stable/accelerator.h>
+#include <torch/csrc/stable/library.h>
+#include <torch/csrc/stable/ops.h>
+#include <torch/csrc/stable/tensor.h>
+#include <torch/headeronly/core/ScalarType.h>
+#include <torch/headeronly/macros/Macros.h>
+
+#include <torch/csrc/stable/c/shim.h>
+
+#include <cuda.h>
+#include <cuda_runtime.h>
+
+namespace extension_cpp_stable {
+
+__global__ void muladd_kernel(int numel, const float *a, const float *b,
+                              float c, float *result) {
+  int idx = blockIdx.x * blockDim.x + threadIdx.x;
+  if (idx < numel)
+    result[idx] = a[idx] * b[idx] + c;
+}
+
+torch::stable::Tensor mymuladd_cuda(const torch::stable::Tensor &a,
+                                    const torch::stable::Tensor &b, double c) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CUDA);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CUDA);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+  torch::stable::Tensor result = torch::stable::empty_like(a_contig);
+
+  const float *a_ptr = a_contig.const_data_ptr<float>();
+  const float *b_ptr = b_contig.const_data_ptr<float>();
+  float *result_ptr = result.mutable_data_ptr<float>();
+
+  int numel = a_contig.numel();
+
+  // For now, we rely on the raw shim API to get the current CUDA stream.
+  // This will be improved in a future release.
+  // When using a raw shim API, we need to use TORCH_ERROR_CODE_CHECK to
+  // check the error code and throw an appropriate runtime_error otherwise.
+  void *stream_ptr = nullptr;
+  TORCH_ERROR_CODE_CHECK(
+      aoti_torch_get_current_cuda_stream(a.get_device_index(), &stream_ptr));
+  cudaStream_t stream = static_cast<cudaStream_t>(stream_ptr);
+
+  muladd_kernel<<<(numel + 255) / 256, 256, 0, stream>>>(numel, a_ptr, b_ptr, c,
+                                                         result_ptr);
+  return result;
+}
+
+__global__ void mul_kernel(int numel, const float *a, const float *b,
+                           float *result) {
+  int idx = blockIdx.x * blockDim.x + threadIdx.x;
+  if (idx < numel)
+    result[idx] = a[idx] * b[idx];
+}
+
+torch::stable::Tensor mymul_cuda(const torch::stable::Tensor &a,
+                                 const torch::stable::Tensor &b) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CUDA);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CUDA);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+  torch::stable::Tensor result = torch::stable::empty_like(a_contig);
+
+  const float *a_ptr = a_contig.const_data_ptr<float>();
+  const float *b_ptr = b_contig.const_data_ptr<float>();
+  float *result_ptr = result.mutable_data_ptr<float>();
+
+  int numel = a_contig.numel();
+
+  // For now, we rely on the raw shim API to get the current CUDA stream.
+  // This will be improved in a future release.
+  // When using a raw shim API, we need to use TORCH_ERROR_CODE_CHECK to
+  // check the error code and throw an appropriate runtime_error otherwise.
+  void *stream_ptr = nullptr;
+  TORCH_ERROR_CODE_CHECK(
+      aoti_torch_get_current_cuda_stream(a.get_device_index(), &stream_ptr));
+  cudaStream_t stream = static_cast<cudaStream_t>(stream_ptr);
+
+  mul_kernel<<<(numel + 255) / 256, 256, 0, stream>>>(numel, a_ptr, b_ptr,
+                                                      result_ptr);
+  return result;
+}
+
+__global__ void add_kernel(int numel, const float *a, const float *b,
+                           float *result) {
+  int idx = blockIdx.x * blockDim.x + threadIdx.x;
+  if (idx < numel)
+    result[idx] = a[idx] + b[idx];
+}
+
+// An example of an operator that mutates one of its inputs.
+void myadd_out_cuda(const torch::stable::Tensor &a,
+                    const torch::stable::Tensor &b,
+                    torch::stable::Tensor &out) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(b.sizes().equals(out.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(out.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(out.is_contiguous());
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CUDA);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CUDA);
+  STD_TORCH_CHECK(out.device().type() == torch::headeronly::DeviceType::CUDA);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+
+  const float *a_ptr = a_contig.const_data_ptr<float>();
+  const float *b_ptr = b_contig.const_data_ptr<float>();
+  float *result_ptr = out.mutable_data_ptr<float>();
+
+  int numel = a_contig.numel();
+
+  // For now, we rely on the raw shim API to get the current CUDA stream.
+  // This will be improved in a future release.
+  // When using a raw shim API, we need to use TORCH_ERROR_CODE_CHECK to
+  // check the error code and throw an appropriate runtime_error otherwise.
+  void *stream_ptr = nullptr;
+  TORCH_ERROR_CODE_CHECK(
+      aoti_torch_get_current_cuda_stream(a.get_device_index(), &stream_ptr));
+  cudaStream_t stream = static_cast<cudaStream_t>(stream_ptr);
+
+  add_kernel<<<(numel + 255) / 256, 256, 0, stream>>>(numel, a_ptr, b_ptr,
+                                                      result_ptr);
+}
+
+// Registers CUDA implementations for mymuladd, mymul, myadd_out
+STABLE_TORCH_LIBRARY_IMPL(extension_cpp_stable, CUDA, m) {
+  m.impl("mymuladd", TORCH_BOX(&mymuladd_cuda));
+  m.impl("mymul", TORCH_BOX(&mymul_cuda));
+  m.impl("myadd_out", TORCH_BOX(&myadd_out_cuda));
+}
+
+} // namespace extension_cpp_stable
diff --git a/extension_cpp_stable/extension_cpp_stable/csrc/muladd.cpp b/extension_cpp_stable/extension_cpp_stable/csrc/muladd.cpp
new file mode 100644
index 0000000..c843c58
--- /dev/null
+++ b/extension_cpp_stable/extension_cpp_stable/csrc/muladd.cpp
@@ -0,0 +1,118 @@
+#include <Python.h>
+
+#include <torch/csrc/stable/library.h>
+#include <torch/csrc/stable/ops.h>
+#include <torch/csrc/stable/tensor.h>
+#include <torch/headeronly/core/ScalarType.h>
+#include <torch/headeronly/macros/Macros.h>
+
+extern "C" {
+  /* Creates a dummy empty _C module that can be imported from Python.
+     The import from Python will load the .so consisting of this file
+     in this extension, so that the STABLE_TORCH_LIBRARY static initializers
+     below are run. */
+  PyObject* PyInit__C(void)
+  {
+      static struct PyModuleDef module_def = {
+          PyModuleDef_HEAD_INIT,
+          "_C",   /* name of module */
+          NULL,   /* module documentation, may be NULL */
+          -1,     /* size of per-interpreter state of the module,
+                     or -1 if the module keeps state in global variables. */
+          NULL,   /* methods */
+      };
+      return PyModule_Create(&module_def);
+  }
+}
+
+namespace extension_cpp_stable {
+
+torch::stable::Tensor mymuladd_cpu(
+    const torch::stable::Tensor& a,
+    const torch::stable::Tensor& b,
+    double c) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CPU);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CPU);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+  torch::stable::Tensor result = torch::stable::empty_like(a_contig);
+
+  const float* a_ptr = a_contig.const_data_ptr<float>();
+  const float* b_ptr = b_contig.const_data_ptr<float>();
+  float* result_ptr = result.mutable_data_ptr<float>();
+
+  for (int64_t i = 0; i < result.numel(); i++) {
+    result_ptr[i] = a_ptr[i] * b_ptr[i] + c;
+  }
+  return result;
+}
+
+torch::stable::Tensor mymul_cpu(
+    const torch::stable::Tensor& a,
+    const torch::stable::Tensor& b) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CPU);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CPU);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+  torch::stable::Tensor result = torch::stable::empty_like(a_contig);
+
+  const float* a_ptr = a_contig.const_data_ptr<float>();
+  const float* b_ptr = b_contig.const_data_ptr<float>();
+  float* result_ptr = result.mutable_data_ptr<float>();
+
+  for (int64_t i = 0; i < result.numel(); i++) {
+    result_ptr[i] = a_ptr[i] * b_ptr[i];
+  }
+  return result;
+}
+
+// An example of an operator that mutates one of its inputs.
+void myadd_out_cpu(
+    const torch::stable::Tensor& a,
+    const torch::stable::Tensor& b,
+    torch::stable::Tensor& out) {
+  STD_TORCH_CHECK(a.sizes().equals(b.sizes()));
+  STD_TORCH_CHECK(b.sizes().equals(out.sizes()));
+  STD_TORCH_CHECK(a.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(b.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(out.scalar_type() == torch::headeronly::ScalarType::Float);
+  STD_TORCH_CHECK(out.is_contiguous());
+  STD_TORCH_CHECK(a.device().type() == torch::headeronly::DeviceType::CPU);
+  STD_TORCH_CHECK(b.device().type() == torch::headeronly::DeviceType::CPU);
+  STD_TORCH_CHECK(out.device().type() == torch::headeronly::DeviceType::CPU);
+
+  torch::stable::Tensor a_contig = torch::stable::contiguous(a);
+  torch::stable::Tensor b_contig = torch::stable::contiguous(b);
+
+  const float* a_ptr = a_contig.const_data_ptr<float>();
+  const float* b_ptr = b_contig.const_data_ptr<float>();
+  float* result_ptr = out.mutable_data_ptr<float>();
+
+  for (int64_t i = 0; i < out.numel(); i++) {
+    result_ptr[i] = a_ptr[i] + b_ptr[i];
+  }
+}
+
+// Defines the operators
+STABLE_TORCH_LIBRARY(extension_cpp_stable, m) {
+  m.def("mymuladd(Tensor a, Tensor b, float c) -> Tensor");
+  m.def("mymul(Tensor a, Tensor b) -> Tensor");
+  m.def("myadd_out(Tensor a, Tensor b, Tensor(a!) out) -> ()");
+}
+
+// Registers CPU implementations for mymuladd, mymul, myadd_out
+STABLE_TORCH_LIBRARY_IMPL(extension_cpp_stable, CPU, m) {
+  m.impl("mymuladd", TORCH_BOX(&mymuladd_cpu));
+  m.impl("mymul", TORCH_BOX(&mymul_cpu));
+  m.impl("myadd_out", TORCH_BOX(&myadd_out_cpu));
+}
+
+}
diff --git a/extension_cpp_stable/extension_cpp_stable/ops.py b/extension_cpp_stable/extension_cpp_stable/ops.py
new file mode 100644
index 0000000..3280fc4
--- /dev/null
+++ b/extension_cpp_stable/extension_cpp_stable/ops.py
@@ -0,0 +1,63 @@
+import torch
+from torch import Tensor
+
+__all__ = ["mymuladd", "myadd_out"]
+
+
+def mymuladd(a: Tensor, b: Tensor, c: float) -> Tensor:
+    """Performs a * b + c in an efficient fused kernel"""
+    return torch.ops.extension_cpp_stable.mymuladd.default(a, b, c)
+
+
+# Registers a FakeTensor kernel (aka "meta kernel", "abstract impl")
+# that describes what the properties of the output Tensor are given
+# the properties of the input Tensor. The FakeTensor kernel is necessary
+# for the op to work performantly with torch.compile.
+@torch.library.register_fake("extension_cpp_stable::mymuladd")
+def _(a, b, c):
+    torch._check(a.shape == b.shape)
+    torch._check(a.dtype == torch.float)
+    torch._check(b.dtype == torch.float)
+    torch._check(a.device == b.device)
+    return torch.empty_like(a)
+
+
+def _backward(ctx, grad):
+    a, b = ctx.saved_tensors
+    grad_a, grad_b = None, None
+    if ctx.needs_input_grad[0]:
+        grad_a = torch.ops.extension_cpp_stable.mymul.default(grad, b)
+    if ctx.needs_input_grad[1]:
+        grad_b = torch.ops.extension_cpp_stable.mymul.default(grad, a)
+    return grad_a, grad_b, None
+
+
+def _setup_context(ctx, inputs, output):
+    a, b, c = inputs
+    saved_a, saved_b = None, None
+    if ctx.needs_input_grad[0]:
+        saved_b = b
+    if ctx.needs_input_grad[1]:
+        saved_a = a
+    ctx.save_for_backward(saved_a, saved_b)
+
+
+# This adds training support for the operator. You must provide us
+# the backward formula for the operator and a `setup_context` function
+# to save values to be used in the backward.
+torch.library.register_autograd(
+    "extension_cpp_stable::mymuladd", _backward, setup_context=_setup_context)
+
+
+@torch.library.register_fake("extension_cpp_stable::mymul")
+def _(a, b):
+    torch._check(a.shape == b.shape)
+    torch._check(a.dtype == torch.float)
+    torch._check(b.dtype == torch.float)
+    torch._check(a.device == b.device)
+    return torch.empty_like(a)
+
+
+def myadd_out(a: Tensor, b: Tensor, out: Tensor) -> None:
+    """Writes a + b into out"""
+    torch.ops.extension_cpp_stable.myadd_out.default(a, b, out)
